function ImageCycleCard({ card, tall }: { card: TeamCard; tall?: boolean }) {
  const containerRef = useRef<HTMLDivElement>(null);
  const indexRef = useRef(card.startIndex % card.members.length);
  const intervalRef = useRef<ReturnType<typeof setInterval> | null>(null);

  useEffect(() => {
    const container = containerRef.current;
    if (!container) return;

    const imgs = container.querySelectorAll<HTMLElement>(".cycle-img");

    const showIndex = (idx: number) => {
      imgs.forEach((img, i) => {
        if (i === idx) {
          img.style.opacity = "1";
          img.style.zIndex = "1";
        } else {
          img.style.opacity = "0";
          img.style.zIndex = "0";
        }
      });
    };

    showIndex(indexRef.current);

    intervalRef.current = setInterval(() => {
      indexRef.current = (indexRef.current + 1) % card.members.length;
      showIndex(indexRef.current);
    }, 1800 + card.id * 200);

    return () => {
      if (intervalRef.current) clearInterval(intervalRef.current);
    };
  }, [card]);

  return (
    <div
      className={`team-card relative overflow-hidden rounded-[1.25em] w-full shadow-2xl bg-[#1a1a1a] ${
        tall ? "aspect-[4/5]" : "aspect-square"
      }`}
    >
      <div ref={containerRef} className="absolute inset-0 w-full h-full">
        {card.members.map((m, i) => (
          <div
            key={i}
            className="cycle-img absolute inset-0 w-full h-full transition-opacity duration-700 opacity-0 z-0"
          >
            {/* eslint-disable-next-line @next/next/no-img-element */}
            <img
              src={m.img}
              alt={m.name}
              className="w-full h-full object-cover"
              loading="lazy"
            />
          </div>
        ))}
      </div>
    </div>
  );
}

